int main() {
    std::string inputLine;
    while (std::getline(std::cin, inputLine)) {
        std::stringstream sStream(inputLine);
        DblDim iW, iH;
        if (!(sStream >> iW >> iH)) {
            std::cerr << "Input parsing failed. Expected two numbers." << std::endl;
            continue;
        }

        Rectangle aRect(iW, iH);
        DblDim finalArea = calculateArea(aRect);

        std::cout << std::fixed << std::setprecision(2) << finalArea << std::endl;
    }
    return 0;
}
